inline void Shift(uint8_t state[4][Nb]) {
    for (int i = 1; i < 4; i++) {
        uint8_t temp[Nb];
        for (int j = 0; j < Nb; j++)
            temp[j] = state[i][(j + i) % Nb];
		memcpy(state[i], temp, Nb);    
	}
	_mm_sfence();
}
__attribute__((always_inline))
inline void InvShift(uint8_t state[4][Nb]) {
    for (int i = 1; i < 4; i++) {
        uint8_t temp[Nb];
        for (int j = 0; j < Nb; j++) {
            temp[j] = state[i][(j - i + Nb) % Nb];
        }
		memcpy(state[i], temp, Nb);	
    }
	_mm_sfence();
}
